// vault-graph-3d.js
// Vanilla ES-module drop-in for AetherCloud-L's vault canvas.
// Renders a 3D force-directed knowledge graph with retro pixel-art file
// icons, ambient 3D starfield, and a "neural-link" agent → web jump.
//
// No React, no JSX, no bundler required. Just import this file from the
// existing dashboard.html and call mountVaultGraph3D(...).
//
// Dependencies (loaded by the host page — see CLAUDE_CODE_PROMPT.md):
//   - three                  (window.THREE)
//   - 3d-force-graph         (window.ForceGraph3D)
//   - three-spritetext       (window.SpriteText)
//
// Public API:
//   const vault = mountVaultGraph3D({
//     container,        // HTMLElement to fill
//     iconBase,         // path prefix for icon PNGs, e.g. "./vault-graph-3d/icons"
//     entries,          // [{ path, size?, references?, locked? }, ...]
//     onQuery,          // async (raw) => string[]  (returns matching node ids)
//     onAgentWeb,       // async (sourceId) => string  (label for star)
//     onNodeOpen,       // (path) => void
//     onChatNotice,     // (markdownString) => void  (push assistant chat message)
//   });
//   vault.update(entries)         // re-render with new vault entries
//   vault.runAgentWeb(sourceId?)  // trigger neural-jump programmatically
//   vault.focus(id)               // fly camera to node id
//   vault.destroy()               // clean up

const ROOT_ID = "__VAULT_ROOT__";

// ===================================================================
// Icon mapping
// ===================================================================
const ICON_FILES = {
  img: "img.png", doc: "doc.png", pdf: "pdf.png", md: "md.png",
  json: "json.png", yaml: "yaml.png", py: "py.png", ts: "ts.png",
  csv: "csv.png", log: "log.png", env: "env.png", bin: "bin.png",
  key: "key.png",
  folder: "folder.png",
  folder_secret: "folder_secret.png",
  folder_doc: "folder_doc.png",
  folder_strategy: "folder_strategy.png",
  folder_model: "folder_model.png",
  folder_sec: "folder_sec.png",
  root: "root.png",
  star: "star.png",
};

// Inlined icon data URLs — required because Electron file:// origin +
// strict CSP `img-src 'self' data:` blocks same-origin file:// image
// fetches (Chromium opaque-origin behavior). Data URLs are explicitly
// allowed by CSP, so we sidestep the path-based loading entirely.
const ICON_DATA_URLS = {
  "img": "data:image/png;base64,",
  "doc": "data:image/png;base64,",
  "pdf": "data:image/png;base64,",
  "md": "data:image/png;base64,",
  "json": "data:image/png;base64,",
  "yaml": "data:image/png;base64,",
  "py": "data:image/png;base64,",
  "ts": "data:image/png;base64,",
  "csv": "data:image/png;base64,",
  "log": "data:image/png;base64,",
  "env": "data:image/png;base64,",
  "bin": "data:image/png;base64,",
  "key": "data:image/png;base64,",
  "folder": "data:image/png;base64,",
  "folder_secret": "data:image/png;base64,",
  "folder_doc": "data:image/png;base64,",
  "folder_strategy": "data:image/png;base64,",
  "folder_model": "data:image/png;base64,",
  "folder_sec": "data:image/png;base64,",
  "root": "data:image/png;base64,",
  "star": "data:image/png;base64,",
};


function iconKeyFor(name, opts) {
  const l = (name || "").toLowerCase();
  if (opts && opts.isRoot) return "root";
  if (opts && opts.isStar) return "star";
  if (opts && opts.isDirectory) {
    if (/secret|config|cred|env/.test(l)) return "folder_secret";
    if (/patent|doc/.test(l)) return "folder_doc";
    if (/trading|strategy/.test(l)) return "folder_strategy";
    if (/model/.test(l)) return "folder_model";
    if (/security|secur/.test(l)) return "folder_sec";
    return "folder";
  }
  if (l.endsWith(".env") || /credentials|secrets|key|\.pem$/.test(l)) return "env";
  if (l.endsWith(".png") || l.endsWith(".jpg") || l.endsWith(".jpeg") || l.endsWith(".gif")) return "img";
  if (l.endsWith(".pdf")) return "pdf";
  if (l.endsWith(".md")) return "md";
  if (l.endsWith(".json")) return "json";
  if (l.endsWith(".yaml") || l.endsWith(".yml")) return "yaml";
  if (l.endsWith(".py")) return "py";
  if (l.endsWith(".ts") || l.endsWith(".tsx") || l.endsWith(".js") || l.endsWith(".jsx")) return "ts";
  if (l.endsWith(".csv")) return "csv";
  if (l.endsWith(".log")) return "log";
  if (l.endsWith(".bin") || l.endsWith(".safetensors") || l.endsWith(".onnx")) return "bin";
  return "doc";
}

const SECRET_NAMES = new Set([".env", "credentials.json", "settings.json", "secrets.json"]);
function defaultLocked(name) {
  const l = (name || "").toLowerCase();
  if (SECRET_NAMES.has(l)) return true;
  if (/credentials|secrets|\.pem$|\.key$/.test(l)) return true;
  if (/audit|vuln|threat/.test(l)) return true;
  if (/strategy|backtest_cfg/.test(l)) return true;
  if (/training_cfg|weights\.bin/.test(l)) return true;
  return false;
}

// ===================================================================
// Build graph from VaultEntry[]
// ===================================================================
function buildVaultGraph(entries) {
  const nodes = new Map();
  const links = [];

  nodes.set(ROOT_ID, {
    id: ROOT_ID, name: "VAULT ROOT", path: "/",
    isDirectory: true, isRoot: true, isStar: false,
    locked: true, val: 36, iconKey: "root",
  });

  const ensureDir = (dirPath) => {
    if (!dirPath || dirPath === "/" || nodes.has(dirPath)) return;
    const segs = dirPath.split("/").filter(Boolean);
    const name = segs[segs.length - 1] + "/";
    nodes.set(dirPath, {
      id: dirPath, name, path: dirPath,
      isDirectory: true, isRoot: false, isStar: false,
      locked: false, val: 20, iconKey: iconKeyFor(name, { isDirectory: true }),
    });
    const parentPath = segs.length > 1 ? segs.slice(0, -1).join("/") : "";
    const parentId = parentPath || ROOT_ID;
    if (parentId !== dirPath) ensureDir(parentPath);
    links.push({ source: parentId, target: dirPath, kind: "parent",
      color: "rgba(94,234,212,0.28)", width: 0.8 });
  };

  for (const entry of entries) {
    const segs = entry.path.split("/").filter(Boolean);
    if (segs.length === 0) continue;
    const fileName = segs[segs.length - 1];
    const parentPath = segs.slice(0, -1).join("/");
    if (parentPath) ensureDir(parentPath);
    const sizeVal = entry.size
      ? Math.max(10, Math.min(22, Math.log2(entry.size + 2) * 1.6))
      : 12;
    nodes.set(entry.path, {
      id: entry.path, name: fileName, path: entry.path,
      isDirectory: false, isRoot: false, isStar: false,
      locked: entry.locked != null ? entry.locked : defaultLocked(fileName),
      val: sizeVal, iconKey: iconKeyFor(fileName),
    });
    links.push({ source: parentPath || ROOT_ID, target: entry.path, kind: "parent",
      color: "rgba(94,234,212,0.28)", width: 0.8 });
  }

  for (const entry of entries) {
    if (!entry.references) continue;
    for (const target of entry.references) {
      if (!nodes.has(entry.path) || !nodes.has(target)) continue;
      links.push({ source: entry.path, target, kind: "reference",
        color: "rgba(34,211,238,0.55)", width: 1.4 });
    }
  }

  return { nodes: [...nodes.values()], links };
}

// ===================================================================
// Mount
// ===================================================================
function mountVaultGraph3D(opts) {
  const {
    container, iconBase = "./icons", entries = [],
    onQuery, onAgentWeb, onNodeOpen, onChatNotice,
  } = opts;
  if (!container) throw new Error("mountVaultGraph3D: container required");
  if (!window.THREE) throw new Error("THREE is not loaded");
  if (!window.ForceGraph3D) throw new Error("ForceGraph3D is not loaded");
  if (!window.SpriteText) throw new Error("SpriteText is not loaded");
  const THREE = window.THREE;
  const ForceGraph3D_ = window.ForceGraph3D;
  const SpriteText = window.SpriteText;
  const CSS3DRenderer = window.CSS3DRenderer;
  const CSS3DSprite = window.CSS3DSprite;
  const HAS_CSS3D = !!(CSS3DRenderer && CSS3DSprite);

  // ---- DOM scaffolding (scoped to container) ----
  container.classList.add("vault-3d-host");
  container.innerHTML = `
    <canvas class="v3d-nebula"></canvas>
    <div class="v3d-graph"></div>
    <div class="v3d-hud-top">
      <div class="v3d-qbar">
        <input class="v3d-q" placeholder="Query the vault…" />
        <button class="v3d-qbtn">Query</button>
        <button class="v3d-webbtn">Agent → Web</button>
      </div>
    </div>
    <div class="v3d-detail" hidden>
      <div class="v3d-name"></div>
      <div class="v3d-path"></div>
      <div class="v3d-meta">
        <span class="v3d-cat"></span>
        <span class="v3d-locked" hidden>LOCKED</span>
      </div>
      <button class="v3d-open" hidden>Open file</button>
    </div>
    <div class="v3d-banner" hidden>
      <span class="v3d-banner-glyph"></span>
      <span class="v3d-banner-text">Agent reaching the web…</span>
    </div>
  `;
  injectStyles();

  const nebula = container.querySelector(".v3d-nebula");
  const graphEl = container.querySelector(".v3d-graph");

  // ---- HTML overlay layer (Phase B v5 — manual screen-space projection) ----
  // We tried CSS3DRenderer + CSS3DSprite (Phase B v4) but it silently
  // produced no visible output, likely because of the dual-Three issue
  // (3d-force-graph's bundled Three vs our top-level Three not matching
  // the camera type CSS3DRenderer expects). The manual approach below is
  // dramatically simpler: project node world positions to screen pixels
  // each frame, place plain <img> elements absolutely. Works with any
  // camera object — only reads its projectionMatrix + matrixWorldInverse.
  // The overlay layer must be a SIBLING of graphEl, NOT a child — 3d-force-graph
  // takes ownership of graphEl and wipes its content on init. We attach the
  // overlay (and diag badge) to `container` (.vault-3d-host) which sits above
  // graphEl in stacking order via z-index.
  const overlayEl = document.createElement("div");
  overlayEl.style.cssText =
    "position:absolute;top:0;left:0;width:100%;height:100%;" +
    "pointer-events:none;z-index:3;overflow:hidden;";
  container.appendChild(overlayEl);
  const iconElMap = new Map(); // nodeId → <img>
  const _projVec = new THREE.Vector3();
  const qInput = container.querySelector(".v3d-q");
  const qBtn = container.querySelector(".v3d-qbtn");
  const webBtn = container.querySelector(".v3d-webbtn");
  const detail = container.querySelector(".v3d-detail");
  const dName = container.querySelector(".v3d-name");
  const dPath = container.querySelector(".v3d-path");
  const dCat = container.querySelector(".v3d-cat");
  const dLock = container.querySelector(".v3d-locked");
  const dOpen = container.querySelector(".v3d-open");
  const banner = container.querySelector(".v3d-banner");
  const bannerText = container.querySelector(".v3d-banner-text");

  // ---- Nebula painter (2D color wash behind 3D scene) ----
  const nctx = nebula.getContext("2d");
  function paintNebula() {
    nebula.width = nebula.clientWidth; nebula.height = nebula.clientHeight;
    const W = nebula.width, H = nebula.height;
    nctx.fillStyle = "#000"; nctx.fillRect(0, 0, W, H);
    const g1 = nctx.createRadialGradient(W*0.7, H*0.3, 0, W*0.7, H*0.3, W*0.55);
    g1.addColorStop(0, "rgba(45,80,120,0.22)"); g1.addColorStop(1, "rgba(0,0,0,0)");
    nctx.fillStyle = g1; nctx.fillRect(0, 0, W, H);
    const g2 = nctx.createRadialGradient(W*0.2, H*0.75, 0, W*0.2, H*0.75, W*0.45);
    g2.addColorStop(0, "rgba(80,40,120,0.18)"); g2.addColorStop(1, "rgba(0,0,0,0)");
    nctx.fillStyle = g2; nctx.fillRect(0, 0, W, H);
    const g3 = nctx.createRadialGradient(W*0.55, H*0.55, 0, W*0.55, H*0.55, W*0.7);
    g3.addColorStop(0, "rgba(15,25,55,0.0)");
    g3.addColorStop(0.7, "rgba(8,14,32,0.4)");
    g3.addColorStop(1, "rgba(0,0,0,0.7)");
    nctx.fillStyle = g3; nctx.fillRect(0, 0, W, H);
  }
  paintNebula();
  const onResize = () => { paintNebula(); fitGraph(); };
  window.addEventListener("resize", onResize);

  // ---- Pre-load icon textures (Phase B v3 cheap fix) ----
  // Per the v0.9.8 reference icon-system.js + the v3 prompt, the magic
  // ingredients to make Sprite+map render in r160 are:
  //   1. Pass an onLoad callback to TextureLoader.load
  //   2. Inside callback set tex.colorSpace = THREE.SRGBColorSpace
  //      (r152+ default changed; PNG decoded as linear without this and
  //      the sprite shader's alpha pipeline misbehaves)
  //   3. Mark every SPRITE MATERIAL that consumed this texture as
  //      needsUpdate = true so the GPU re-uploads the bound texture
  // Combined with sprite material alphaTest: 0.01 + renderOrder: 10
  // (set in makeIconSprite below) this is the cheap fix before falling
  // back to a raw Three migration.
  // ---- Pre-load icon textures (verbatim from new icon pack INSTALL.md) ----
  // The new icon pack at desktop/pages/vault-graph-3d/icons/*.png ships
  // optimized 1024×1024 PNGs (~6KB each) designed for this exact loader
  // pattern. Path-based loading per INSTALL.md spec — file:// + img-src
  // 'self' resolves cleanly for same-origin same-folder PNGs.
  const TEX = {};
  const loader = new THREE.TextureLoader();
  for (const [k, file] of Object.entries(ICON_FILES)) {
    // Prefer the inlined data URL (always CSP-safe under file:// origin);
    // fall back to the file path if the data URL isn't baked in.
    const url = ICON_DATA_URLS[k] || `${iconBase}/${file}`;
    TEX[k] = loader.load(url, function (t) {
      if (THREE.SRGBColorSpace) t.colorSpace = THREE.SRGBColorSpace;
      t.minFilter  = THREE.LinearMipmapLinearFilter;
      t.magFilter  = THREE.LinearFilter;
      t.anisotropy = 16;
      t.needsUpdate = true;
    });
  }

  // ---- Graph instance ----
  const Graph = ForceGraph3D_()(graphEl)
    .backgroundColor("rgba(0,0,0,0)")
    .showNavInfo(false)
    .nodeThreeObject(makeIconSprite)
    .nodeThreeObjectExtend(false)
    .nodeRelSize(0)
    .nodeOpacity(0)
    .onEngineTick(() => syncIconOverlay())
    .linkColor(l => l.color)
    .linkWidth(l => l.width)
    .linkOpacity(0.6)
    .linkDirectionalParticles(l => l.kind === "reference" ? 2 : 0)
    .linkDirectionalParticleWidth(1.8)
    .linkDirectionalParticleColor(() => "#22d3ee")
    .linkDirectionalParticleSpeed(0.006)
    .onNodeHover(n => { graphEl.style.cursor = n ? "pointer" : "default"; })
    .onNodeClick(n => {
      lastClickedSourceId = n.id;
      showDetail(n);
      flyTo(n, 110);
    })
    .onBackgroundClick(() => { detail.hidden = true; });

  Graph.d3VelocityDecay(0.28);
  Graph.d3Force("link").distance(85);
  Graph.d3Force("charge").strength(-340);

  // ---- HTML overlay per-frame projection loop (Phase B v5) ----
  // Each frame: for every graph node, project its 3D world position to
  // screen pixels using the camera's projectionMatrix · matrixWorldInverse,
  // and translate the matching <img> element. Hide nodes behind the camera.
  function syncIconOverlay() {
    const cam = Graph.camera && Graph.camera();
    if (!cam) return;
    const r = overlayEl.getBoundingClientRect();
    const W = r.width, H = r.height;
    if (W === 0 || H === 0) return;
    const data = Graph.graphData();
    const seenIds = new Set();
    for (const node of data.nodes) {
      seenIds.add(node.id);
      const img = iconElMap.get(node.id);
      if (!img) continue;
      if (typeof node.x !== "number") continue;
      _projVec.set(node.x, node.y, node.z);
      _projVec.project(cam);
      if (_projVec.z > 1 || _projVec.z < -1) {
        img.style.display = "none";
        continue;
      }
      const sx = (_projVec.x * 0.5 + 0.5) * W;
      const sy = (-_projVec.y * 0.5 + 0.5) * H;
      const depth = (1 - _projVec.z) * 0.5;
      const scale = 0.4 + depth * 0.8;
      img.style.display = "";
      img.style.transform =
        "translate(-50%, -50%) translate(" + sx + "px, " + sy + "px) " +
        "scale(" + scale.toFixed(3) + ")";
    }
    for (const [id, img] of iconElMap.entries()) {
      if (!seenIds.has(id)) {
        img.remove();
        iconElMap.delete(id);
      }
    }
  }
  (function overlayRenderLoop() {
    try { syncIconOverlay(); } catch (_) {}
    requestAnimationFrame(overlayRenderLoop);
  })();

  // Per-file-type color palette. We tried SpriteMaterial+map and
  // MeshBasicMaterial+map approaches for the original pixel-art PNGs;
  // both rendered fully invisible in this Electron + 3d-force-graph + Three
  // r160 combination (verified via diagnostic boxes: solid Mesh renders,
  // any material with `map` does not). The starfield works because it
  // uses PointsMaterial with AdditiveBlending — a different code path.
  // Until we resolve the texture-upload issue (likely during Galaxy work
  // when we may switch the renderer entirely), ship distinct file-type
  // colors on geometric primitives — clean, readable, no texture deps.
  const TYPE_COLOR = {
    img: 0xfb923c, doc: 0xf87171, pdf: 0xef4444, md: 0xfca5a5,
    json: 0xa78bfa, yaml: 0xc4b5fd, py: 0x86efac, ts: 0xfbbf24,
    csv: 0xddd6fe, log: 0x94a3b8, env: 0xf59e0b, bin: 0xa1a1aa,
    key: 0xfde047,
    folder: 0x60a5fa,
    folder_secret: 0xfb7185,
    folder_doc: 0xfca5a5,
    folder_strategy: 0x22d3ee,
    folder_model: 0xc084fc,
    folder_sec: 0xf97316,
    root: 0x5eead4,
    star: 0xa78bfa,
  };

  // makeIconSprite — uses THREE.Points + textured PointsMaterial as the
  // node visual. PointsMaterial+map is the ONLY texture path that renders
  // in this Electron+Three+3d-force-graph WebGL context (verified via
  // controlled diagnostics during Phase A — SpriteMaterial+map and
  // MeshBasicMaterial+map both render fully invisible, but PointsMaterial+map
  // works because the starfield uses it). Textures are pre-created
  // SpriteMaterial-cached but the Points material is fresh per node.
  // Icon size (px) per logical node. Matched to old WebGL sprite sizes so
  // the visual scale lines up with edges/halos.
  function iconPixelSize(node) {
    return Math.round(node.val * (node.isRoot ? 4.5 : 3.6));
  }

  // Register an HTML <img> overlay for this node. Created once, sized by
  // node.val, positioned each frame via syncIconOverlay above.
  function ensureIconOverlay(node) {
    if (iconElMap.has(node.id)) return;
    const img = document.createElement("img");
    img.draggable = false;
    img.alt = node.iconKey || "";
    // CSP-safe: use the inlined data URL — file:// is blocked.
    const iconKey = ICON_FILES[node.iconKey] ? node.iconKey : "doc";
    img.src = ICON_DATA_URLS[iconKey] || `${iconBase}/${ICON_FILES[iconKey]}`;
    const px = iconPixelSize(node);
    img.style.cssText =
      "position:absolute;top:0;left:0;width:" + px + "px;height:" + px + "px;" +
      "transform-origin:50% 50%;will-change:transform;display:none;" +
      "user-select:none;-webkit-user-drag:none;pointer-events:none;" +
      "image-rendering:pixelated;";
    img.onerror = function () { console.warn("[vault3d] icon img load failed:", iconKey); };
    overlayEl.appendChild(img);
    iconElMap.set(node.id, img);
  }

  function makeIconSprite(node) {
    const group = new THREE.Group();
    if (node.isStar) {
      // Purple glowing orb for remote/web stars (kept in WebGL — it's
      // additive blending, not a textured map, so the broken upload path
      // doesn't apply).
      const halo = new THREE.Mesh(
        new THREE.SphereGeometry(node.val * 0.9, 16, 12),
        new THREE.MeshBasicMaterial({
          color: 0xa78bfa, transparent: true, opacity: 0.6,
          depthWrite: false, blending: THREE.AdditiveBlending,
        }),
      );
      group.add(halo);
      group.userData.haloMat = halo.material;
    }
    // Phase B v5 — register an HTML <img> in the overlay layer. It is
    // positioned per frame by syncIconOverlay using camera projection.
    ensureIconOverlay(node);
    if (node.locked && !node.isDirectory && !node.isRoot) {
      const lockGeom = new THREE.PlaneGeometry(node.val * 0.42, node.val * 0.42);
      const lockMat = new THREE.MeshBasicMaterial({
        color: 0xf59e0b, transparent: true, opacity: 0.95,
      });
      const lock = new THREE.Mesh(lockGeom, lockMat);
      lock.position.set(node.val * 0.5, node.val * 0.5, 0.5);
      lock.renderOrder = 11;
      group.add(lock);
      const innerGeom = new THREE.PlaneGeometry(node.val * 0.18, node.val * 0.22);
      const innerMat = new THREE.MeshBasicMaterial({ color: 0xfffbeb });
      const inner = new THREE.Mesh(innerGeom, innerMat);
      inner.position.set(node.val * 0.5, node.val * 0.55, 0.6);
      inner.renderOrder = 12;
      group.add(inner);
    }
    const label = new SpriteText(node.name);
    label.color = node.isRoot ? "#5eead4" : node.isStar ? "#c4b5fd" : "#e2e8f0";
    label.backgroundColor = "rgba(2,6,23,0.55)";
    label.padding = 2; label.borderRadius = 3;
    label.textHeight = node.isRoot || node.isStar ? 5.5 : 3.4;
    label.position.set(0, -node.val * 0.85, 0);
    group.add(label);
    return group;
  }

  function fitGraph() {
    const r = graphEl.getBoundingClientRect();
    Graph.width(r.width); Graph.height(r.height);
  }
  fitGraph();

  // ---- 3D star shells ----
  function makeStarTexture() {
    const cv = document.createElement("canvas");
    cv.width = cv.height = 64;
    const ctx = cv.getContext("2d");
    const g = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
    g.addColorStop(0, "rgba(255,255,255,1)");
    g.addColorStop(0.25, "rgba(255,255,255,0.85)");
    g.addColorStop(0.55, "rgba(255,255,255,0.25)");
    g.addColorStop(1, "rgba(255,255,255,0)");
    ctx.fillStyle = g; ctx.fillRect(0, 0, 64, 64);
    const tex = new THREE.CanvasTexture(cv);
    tex.minFilter = THREE.LinearMipmapLinearFilter;
    tex.magFilter = THREE.LinearFilter;
    return tex;
  }

  // Shared circular sprite texture for file/folder/root node Points.
  // Cached in module scope (not per-mount) so identical instances share GPU memory.
  let _circleTex = null;
  function getCircleTex() {
    if (_circleTex) return _circleTex;
    const cv = document.createElement("canvas");
    cv.width = cv.height = 64;
    const ctx = cv.getContext("2d");
    const g = ctx.createRadialGradient(32, 32, 0, 32, 32, 30);
    g.addColorStop(0,    "rgba(255,255,255,1)");
    g.addColorStop(0.55, "rgba(255,255,255,0.92)");
    g.addColorStop(0.85, "rgba(255,255,255,0.4)");
    g.addColorStop(1,    "rgba(255,255,255,0)");
    ctx.fillStyle = g; ctx.fillRect(0, 0, 64, 64);
    _circleTex = new THREE.CanvasTexture(cv);
    _circleTex.minFilter = THREE.LinearMipmapLinearFilter;
    _circleTex.magFilter = THREE.LinearFilter;
    return _circleTex;
  }
  function buildStarShell(starTex, count, rMin, rMax, size, opacity, tints) {
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      const u = Math.random(), v = Math.random();
      const theta = 2 * Math.PI * u, phi = Math.acos(2 * v - 1);
      const r = rMin + Math.random() * (rMax - rMin);
      positions[i*3]   = r * Math.sin(phi) * Math.cos(theta);
      positions[i*3+1] = r * Math.cos(phi);
      positions[i*3+2] = r * Math.sin(phi) * Math.sin(theta);
      const tint = tints[Math.floor(Math.random() * tints.length)];
      colors[i*3]   = tint[0]; colors[i*3+1] = tint[1]; colors[i*3+2] = tint[2];
    }
    const geom = new THREE.BufferGeometry();
    geom.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    geom.setAttribute("color",    new THREE.BufferAttribute(colors, 3));
    const mat = new THREE.PointsMaterial({
      size, map: starTex, vertexColors: true,
      transparent: true, opacity, depthWrite: false,
      blending: THREE.AdditiveBlending, sizeAttenuation: true,
    });
    return new THREE.Points(geom, mat);
  }
  const COMMON = [[1,1,1], [0.85,0.92,1], [0.96,0.96,0.78]];
  const ACCENT = [[0.65,0.55,0.98], [0.37,0.92,0.83], [0.13,0.83,0.93], [1,0.9,0.55]];
  setTimeout(() => {
    const scn = Graph.scene();
    const tex = makeStarTexture();
    scn.add(buildStarShell(tex, 1800, 1400, 1800, 5,  0.85, COMMON));
    scn.add(buildStarShell(tex,  600,  850, 1200, 8,  0.90, COMMON));
    scn.add(buildStarShell(tex,  140,  500,  750, 14, 1.00, [...COMMON, ...ACCENT, ...ACCENT]));
  }, 50);

  // ---- Auto orbit + initial camera ----
  setTimeout(() => {
    const ctrls = Graph.controls();
    if (ctrls) { ctrls.autoRotate = true; ctrls.autoRotateSpeed = 0.32; }
    Graph.cameraPosition({ x: 0, y: 0, z: 240 });
  }, 600);

  // ---- Initial data ----
  let currentData = buildVaultGraph(entries);
  Graph.graphData(currentData);

  function update(newEntries) {
    currentData = buildVaultGraph(newEntries);
    Graph.graphData(currentData);
  }

  // ---- Detail card ----
  function showDetail(n) {
    detail.hidden = false;
    dName.textContent = n.name;
    dPath.textContent = n.id === ROOT_ID ? "/" : "/" + n.id;
    dCat.textContent = n.isStar ? "remote source" :
                       n.isDirectory ? "directory" :
                       n.isRoot ? "root" : "file";
    dCat.style.color = n.isStar ? "#c4b5fd" : "#5eead4";
    dLock.hidden = !n.locked;
    if (onNodeOpen && !n.isStar && !n.isDirectory && !n.isRoot) {
      dOpen.hidden = false;
      dOpen.onclick = () => onNodeOpen(n.path);
    } else {
      dOpen.hidden = true; dOpen.onclick = null;
    }
  }

  function flyTo(n, dist = 90) {
    if (n.x === undefined) return;
    const ratio = 1 + dist / Math.hypot(n.x || 1, n.y || 1, n.z || 1);
    Graph.cameraPosition({ x: n.x * ratio, y: n.y * ratio, z: n.z * ratio }, n, 1100);
  }
  function focus(id) {
    const n = currentData.nodes.find(x => x.id === id);
    if (n) flyTo(n, 90);
  }

  // ---- Query handler (delegates to host's smart resolver) ----
  async function runQuery() {
    const raw = qInput.value.trim();
    if (!raw) return;
    let matches = [];
    if (onQuery) {
      try { matches = (await onQuery(raw)) || []; } catch (e) { console.error(e); }
    } else {
      const q = raw.toLowerCase();
      matches = currentData.nodes
        .filter(n => n.name.toLowerCase().includes(q) || n.id.toLowerCase().includes(q))
        .map(n => n.id);
    }
    if (matches[0]) focus(matches[0]);
  }
  qBtn.addEventListener("click", runQuery);
  qInput.addEventListener("keydown", e => { if (e.key === "Enter") runQuery(); });

  // ---- Neural-link agent → web jump ----
  let lastClickedSourceId = null;
  let jumping = false;

  async function runAgentWeb(sourceId) {
    if (jumping) return;
    const data = Graph.graphData();
    const candidates = data.nodes.filter(n => !n.isDirectory && !n.isRoot && !n.isStar);
    const source = data.nodes.find(n => n.id === (sourceId || lastClickedSourceId))
                || candidates[Math.floor(Math.random() * candidates.length)];
    if (!source) return;
    jumping = true;

    let starName = "web.search";
    if (onAgentWeb) {
      try { const v = await onAgentWeb(source.id); if (v) starName = v; }
      catch (e) { console.error(e); }
    }

    const theta = Math.random() * Math.PI * 2;
    const phi = (Math.random() - 0.5) * Math.PI * 0.4;
    const dist = 320;
    const tx = Math.cos(phi) * Math.cos(theta) * dist;
    const ty = Math.sin(phi) * dist + 40;
    const tz = Math.cos(phi) * Math.sin(theta) * dist;

    Graph.cameraPosition({ x: 0, y: 0, z: 480 }, undefined, 1100);

    const starId = "web::" + Math.random().toString(36).slice(2, 8);
    const star = {
      id: starId, name: starName, path: "web://" + starName,
      isDirectory: false, isRoot: false, isStar: true,
      locked: false, val: 14, iconKey: "star",
      fx: tx, fy: ty, fz: tz,
    };
    const beam = { source: source.id, target: starId, kind: "neural",
      color: "rgba(167,139,250,0.0)", width: 0.001 };
    const gd = Graph.graphData();
    gd.nodes.push(star); gd.links.push(beam);
    Graph.graphData(gd);

    const orbMat = new THREE.SpriteMaterial({
      color: 0xa78bfa, transparent: true, opacity: 1,
      blending: THREE.AdditiveBlending, depthWrite: false,
    });
    const orb = new THREE.Sprite(orbMat);
    orb.scale.set(8, 8, 1);
    Graph.scene().add(orb);

    banner.hidden = false;
    bannerText.textContent = "Searching the web for related signals…";

    const start = performance.now();
    const dur = 2200;
    return new Promise(resolve => {
      function step(now) {
        const t = Math.min(1, (now - start) / dur);
        const e = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
        const liveSrc = Graph.graphData().nodes.find(n => n.id === source.id);
        const sx = liveSrc.x || 0, sy = liveSrc.y || 0, sz = liveSrc.z || 0;
        const mx = (sx + tx) / 2;
        const my = (sy + ty) / 2 + 60;
        const mz = (sz + tz) / 2;
        orb.position.set(
          (1-e)*(1-e)*sx + 2*(1-e)*e*mx + e*e*tx,
          (1-e)*(1-e)*sy + 2*(1-e)*e*my + e*e*ty,
          (1-e)*(1-e)*sz + 2*(1-e)*e*mz + e*e*tz
        );
        orb.scale.setScalar(8 + Math.sin(now * 0.012) * 1.5);
        const liveBeam = Graph.graphData().links.find(l => l === beam);
        if (liveBeam) {
          liveBeam.color = `rgba(167,139,250,${0.15 + 0.6 * e})`;
          liveBeam.width = 0.6 + 1.4 * e;
        }
        if (t < 1) requestAnimationFrame(step);
        else {
          let f = 1;
          (function fade() {
            f -= 0.04;
            orbMat.opacity = Math.max(0, f);
            if (f > 0) requestAnimationFrame(fade);
            else Graph.scene().remove(orb);
          })();
          setTimeout(() => { banner.hidden = true; }, 1400);
          jumping = false;
          resolve(starId);
        }
      }
      requestAnimationFrame(step);
    });
  }
  webBtn.addEventListener("click", () => runAgentWeb());

  // ---- Cleanup ----
  function destroy() {
    window.removeEventListener("resize", onResize);
    try { Graph._destructor && Graph._destructor(); } catch (_) {}
    container.innerHTML = "";
    container.classList.remove("vault-3d-host");
  }

  return { update, runAgentWeb, focus, destroy, _Graph: Graph };
}

